export const publications = [
  {
    id: 1,
    title: "A 3D P-Wave Model of the Crust and Uppermost Mantle Beneath the Malay Peninsula",
    authors: "Abel Uyimwen Osagie",
    journal: "Asian Journal of Geological Research",
    volume: "8(3)",
    pages: "471–502",
    year: 2025,
    doi: "10.9734/ajoger/2024/v7i3182",
    download: "https://drive.google.com/uc?export=download&id=1za-TmlRYliUcLuUDBb3CFO5gWJTLI8nZ",
    tag: "Seismology",
    abstract: `This study employed a computationally efficient Fortran algorithm to construct a three-dimensional P-wave velocity model of the crust and uppermost mantle beneath the Malay Peninsula (MP). Earthquake datasets from both the International Seismological Centre and the Incorporated Research Institutions for Seismology are used to calculate travel-times. Station corrections are determined prior to inversion based on the ak135 model, considering four back-azimuthal directions. The resulting model, validated against previous regional tomographic studies provide enhanced resolution through finer grid parameterization. The inversion results reflect the complex geological and tectonic framework of the MP. At shallow depths (5–10 km), localised velocity variations correspond to known geological formations. The low-velocity anomalies (LVAs) in the crust are consistent with extensive Cenozoic sedimentary basins and reactivated fault zones. The presence of numerous hot springs along the western belt of the MP suggests elevated thermal activity as a key contributor to the LVAs. Deeper anomalies in the lower crust and upper mantle are attributed to multiple subduction and accretion events, remnant subducted slabs, and mantle flow processes. The result of this study reinforces the hypothesis of asthenospheric upwelling and lateral flow beneath the MP, as proposed by previous researchers. The final P-wave velocity model is used to derive S-wave velocity, density, and Poisson's ratio using established empirical relationships. The algorithm offers a cost-effective and rapid solution for seismic tomography, making it useful for foundational studies in regions with sparse station networks and poor azimuthal coverage, such as the MP and other areas with regional proximity to earthquake-prone zones.`
  },
  {
    id: 2,
    title: "Multi-Scale Seismic Tomography in Rift Zones: Implications for Lithospheric Evolution in the Afar Region",
    authors: "Abel Uyimwen Osagie and Abu Mallam",
    journal: "Asian Journal of Geological Research",
    volume: "8(3)",
    pages: "392–417",
    year: 2025,
    doi: "10.9734/ajoger/2025/v8i3206",
    download: "https://drive.google.com/uc?export=download&id=1UuUPKg9Z9Ec4DNInFfFtuTbIDV6phdGN",
    tag: "Seismology",
    abstract: `The Afar Depression, a nascent oceanic basin within the East African Rift system, offers a unique natural laboratory to investigate the interplay between mantle dynamics and continental breakup. This study employs seismic travel-time tomography to elucidate the interplay between deep mantle dynamics and surface tectonics beneath the Afar region, encompassing northern Ethiopia, Eritrea, Djibouti, northwestern Somalia, and southern Yemen. Utilising 17,476 first-arrival P-waves from 2,911 earthquakes recorded at 114 seismic stations between 1976 and 2023, a 3D P-wave velocity model is developed to a depth of 70 km. The analysis incorporated three different grid resolutions (0.25°, 0.5°, and 1.0°) to optimise the balance between detailed resolution and robust structural imaging. Checkerboard and structural reconstruction tests confirm good resolution across most of the study area. The resulting tomographic images reveal significant velocity heterogeneity throughout the region, with prominent Low-Velocity Zones (LVZs) beneath tectonically active areas including the Afar Depression, Red Sea Rift, Gulf of Aden Rift, and Main Ethiopian Rift. These LVZs extend from shallow depths to 70 km, suggesting the presence of thermally perturbed lithosphere, partial melting, and active magmatism. Conversely, High-Velocity Zones (HVZs) predominate beneath the more stable Nubian, Arabian, and Somalian plates, indicating cooler and thicker lithosphere. The spatial distribution of earthquakes along boundaries between velocity anomalies further supports the relationship between seismic activity and tectonic stress at interfaces between hot, weak mantle material and cooler, stronger lithosphere. Our findings contribute to the understanding of how mantle dynamics influence continental breakup and incipient seafloor spreading in plume-assisted rift systems, supporting models of passive upwelling beneath magmatic segments driven by far-field stresses and buoyancy-related processes.`
  },
  {
    id: 3,
    title: "Traveltime Residual Estimation for some Seismic Stations within Southeast Asia using a New Ray Tracing Algorithm",
    authors: "Abel Uyimwen Osagie and Oke Israel Okwokwo",
    journal: "IOSR Journal of Applied Geology and Geophysics",
    volume: "10(1)",
    pages: "12–20",
    year: 2022,
    doi: "10.9790/0990-1001011220",
    download: "https://drive.google.com/uc?export=download&id=1_upzj6BGNikBQqbSVzzNFInNkm_ewR3W",
    tag: "Seismology",
    abstract: `Path dependent corrections relative to traveltimes have been demonstrated to improve event locations. Using available global velocity models, direction-based station corrections can be estimated in a region without calibration data. In this study, traveltime corrections have been obtained for 113 broadband seismic stations within southern Thailand, Peninsular Malaysia, Singapore and Sumatra region of Indonesia. A total of 97,124 first-arrival p-waves are obtained from 15,180 earthquakes that have occurred around the Sumatra Subduction Zone between 1964 and 2018. The dataset is a combination of arrival times from the bulletin of International Seismological Centre and waveforms from the Incorporated Research Institutions for Seismology. A new algorithm for three-dimensional ray tracing is used to compute traveltimes and raypaths. The corrections are based on the ak135 velocity models at four back-azimuthal directions. Stations with 100 or more arrivals are selected in this study. Station KULM in Peninsular Malaysia recorded the highest number with 5425 arrivals. The estimated residuals range from -0.02 to 0.76 seconds (s) for stations distributed around southern Thailand and a range of 0.48 to 1.09 s for stations within Peninsular Malaysia. A range of 0.37 to 0.54 s for stations within Singapore and -0.55 to 2.04 s for stations distributed around Sumatra (in Indonesia). Stations LEM, KLM and KGM show consistent high residual values at all calculated angles and distances. The result of this study will support routine location of hypocentral parameters within the region. The scheme has been implemented in the forward computational process of a seismic tomographic inversion program.`
  },
  {
    id: 4,
    title: "Structural trends and basement depths across Nigeria from analysis of aeromagnetic data",
    authors: "Abel Uyimwen Osagie, Abdelhakim Eshanibli, Adekunle Abraham Adepelumi",
    journal: "Journal of African Earth Sciences",
    volume: "178(104184)",
    pages: "",
    year: 2021,
    doi: "10.1016/j.jafrearsci.2021.104184",
    download: "https://drive.google.com/uc?export=download&id=1C4rPqSaXuAiFYklWXByYspQpjOo4sFR7",
    tag: "Potential Field Methods",
    abstract: `This study analyses Aeromagnetic Survey Data to delineate magnetic lineaments associated with fault system trends across Nigeria. A High-Pass filter is used to separate the Total Magnetic Intensity's regional and residual components. A filter like Total Horizontal Gradient, Grid Analysis and Tilt Angle derivative are used to enhance the structural trends and fault systems that predominantly trend Northeast-Southwest and East-West. Some of the magnetic signatures on the southern and northeastern Nigeria follow the rift system trend that connects the South Atlantic and inland West Africa. The Euler deconvolution depth estimate of faults range between 1840 and 6321 m (meters) across the region. The Werner deconvolution and two-dimensional forward modelling are used to infer sedimentary thicknesses beneath ten profiles (each profile traverses a major river basin in the country). The estimated depths to basement range between 1500 and 7500 m beneath the Cross-River Basin (in the south) and the Gongola Basin (in the northeast). The Hadejia River Basin in northeast Nigeria is characterised by distinct magnetic anomaly lows and a shallow depth to the basement. Further investigation of this basin is recommended.`
  },
  {
    id: 5,
    title: "Seismic tomographic imaging of P-wave velocity perturbation beneath Sumatra, Java, Malacca Strait, Peninsular Malaysia and Singapore",
    authors: "Abel Uyimwen Osagie and Ismail Ahmad Abir",
    journal: "Journal of Earth System Science",
    volume: "",
    pages: "",
    year: 2020,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1-Z5P0xo8qhFxvV9RR9m7_I-6w__-qD2i",
    tag: "Seismology",
    abstract: `P wave tomographic imaging of the crust down to a depth of 90 km is performed beneath the region encompassing Sumatra, Java, Malacca Strait, peninsular Malaysia and Singapore. Inversion is performed with 99,741 first-arrival p waves from 16,196 local and regional earthquakes occurred around the Sumatra Subduction Zone (SSZ) between 1964 and 2018. Tomographic results show low-velocity (low-V) anomalies that reflect both accretion and possibly, asthenospheric upwelling associated with subduction of the Australian Plate beneath Eurasia around the SSZ. The prominent low-V anomaly is thickest around the Conrad, extending beneath Straits of Malacca and parts of peninsular Malaysia, but disappears around the Moho in the region. Below the Moho, the subducting slab, represented by a high-velocity (high-V) anomaly, trends in the orientation of Sumatra. At these depths, the eastern shorelines of Sumatra, most parts of Malacca Strait and the west coast of peninsular Malaysia show varying degrees of positive velocity anomalies. We consider that asthenospheric upwelling around the SSZ may provide heat source for the 40 or more hot springs distributed north-south in peninsular Malaysia. Different east-west and north-south cross-sections reveal the subsurface anomalies at various parts of the region. The predominant low-V anomaly is less than 35 km in depth, but other low-V anomalies are deeper.`
  },
  {
    id: 6,
    title: "Seismic Traveltime Analysis for Some Stations around Parkfield, California",
    authors: "Abel U. Osagie, Adepelumi A. A., and Falade A. H.",
    journal: "International Journal of Scientific & Engineering Research",
    volume: "11(5)",
    pages: "907–919",
    year: 2020,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1HspfCJykwc6bbE7U8QsoTX2x6qfIKQqO",
    tag: "Seismology",
    abstract: `Digital seismic records of Northern California Seismic Network (NCSN) covering a period of three years (from 1st January, 2010 to 31st December, 2012) have been used to investigate the average traveltime residuals of some seismic stations in the vicinity of Parkfield. During this period, 199 stations records of 61315 P-wave arrival-time picks, and 6366 S-wave arrival-time picks from a total of 1911 events were used for this study. Synthetic traveltimes were generated using the United State Geological Survey (USGS)1-D P-wave velocity model that incorporates a customized two-point ray tracing algorithm. The velocity model obtained suggests that refracted waves are likely the first-arrival phases at most of the Parkfield seismic stations. Comparison between the recorded data set and the synthetic traveltimes show that more than 99% of the Pwave arrival times recorded by each station have traveltime residual values between -2s and +2s. The comparison also show positive average residual values between 0.11s and 0.75s for some stations which include: BMS, PAR, PDR, PJC and WRD. However, most of the stations show negative average residuals that range from -1.28s for station BCW to -0.05s for station B900.It is deduced that the computed average residuals can reduce errors attributable to station correction in the inversion of hypocentral parameters in the vicinity of the study region.`
  },
  {
    id: 7,
    title: "Regional travel-time residual studies and station correction from 1-D velocity models for some stations around Peninsular Malaysia and Singapore",
    authors: "Abel U. Osagie, Mohd. Nawawi, Amin Esmail Khalil and Khiruddin Abdullah",
    journal: "NRIAG Journal of Astronomy and Geophysics",
    volume: "6(1)",
    pages: "19–29",
    year: 2017,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1rICkoi05w558W6BveX7Jkk9MDi3JrS2P",
    tag: "Seismology",
    abstract: `We have investigated the average P-wave travel-time residuals for some stations around Southern Thailand, Peninsular Malaysia and Singapore at regional distances. Six years (January, 2010-December, 2015) record of events from central and northern Sumatra was obtained from the digital seismic archives of Integrated Research Institute for Seismology (IRIS). The criteria used for the data selection are designed to be above the magnitude of mb 4.5, depth less than 200km and an epicentral distance shorter than 1000km. Within this window a total number of 152 earthquakes were obtained. Furthermore, data were filtered based on the clarity of the seismic phases that are manually picked. A total of 1088 P-wave arrivals and 962 S-wave arrivals were hand-picked from 10 seismic stations around the Peninsula. Three stations IPM, KUM, and KOM from Peninsular Malaysia, four stations BTDF, NTU, BESC and KAPK from Singapore and three stations SURA, SRIT and SKLT located in the southern part of Thailand are used. Station NTU was chosen as the Ref. station because it recorded the large number of events. Travel-times were calculated using three 1-D models (Preliminary Ref. Earth Model PREM (Dziewonski and Anderson, 1981, IASP91, and Lienert et al., 1986) and an adopted two-point ray tracing algorithm. For the three models, we corroborate our calculated travel-times with the results from the use of TAUP travel-time calculation software. Relative to station NTU, our results show that the average P wave travel-time residual for PREM model ranges from -0.16 to 0.45s for BESC and IPM respectively. For IASP91 model, the average residual ranges from -0.25 to 0.24s for SRIT and SKLT respectively, and ranges from -0.22 to 0.30s for KAPK and IPM respectively for Lienert et al. (1986) model. Generally, most stations have slightly positive residuals relative to station NTU. These corrections reflect the difference between actual and estimated model velocities along ray paths to stations and can compensate for heterogeneous velocity structure near individual stations. The computed average travel-time residuals can reduce errors attributable to station correction in the inversion of hypocentral parameters around the Peninsula. Due to the heterogeneity occasioned by the numerous fault systems, a better 1-D velocity model for the Peninsula is desired for more reliable hypocentral inversion and other seismic investigations.`
  },
  {
    id: 8,
    title: "Students Record Analysis and Examination Result Computation Algorithm (SRAERCA)",
    authors: "Abel U. Osagie and Abu Mallam",
    journal: "International Journal of Technology Enhancements and Emerging Engineering Research",
    volume: "2(8)",
    pages: "49–59",
    year: 2014,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1sKy5DRghgqVqiUVQwmlCggVWk9FPgx4l",
    tag: "Educational Technology",
    abstract: `There are different computer programs in different tertiary institutions for computing examination results. However, beyond examination result computation, not many programs in use provide multi-level aggregated data of student population and academic progress at various stages of studentship. The need for data use to inform administrative decisions in tertiary institutions have been emphasized. Analysis of students data and academic record can promote data-informed decisions for the purposes of better planning. The Student Record Analysis and Examination Result Computation Algorithm (SRAERCA) is a comprehensive solution for use in tertiary institutions. The algorithm incorporates the entire computational process related to a student from admission to graduation and beyond. The algorithm is modified with the flexibility to accommodate future needs and eliminate delays in examination result computation, preparation of examination result summaries and generation of academic transcripts. A test of resilience, accuracy and analytic capabilities of the algorithm produced expected results. The stages of computation are simple and fast. With a proper file naming system, the output files in all stages are arranged meticulously. The algorithm provides an array of output dataset that satisfies the needs of the students themselves, the course instructor, the department, and the Faculty/College. The computational processes progressively catalog important statistics about student population and their academic performances to encourage data use and for future reference. Ultimately, the algorithm provides information and analysis for data-informed decisions toward a more professional culture in tertiary institutions.`
  },
  {
    id: 9,
    title: "Relocation of Earthquakes that Occurred Beneath Parkfield Region of California using VELHYPO",
    authors: "Abel U. Osagie and Woohan Kim",
    journal: "IOSR Journal of Applied Geology and Geophysics",
    volume: "1(3)",
    pages: "66–81",
    year: 2013,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1DfeoxyY-siHadNIoXbOWtuuOw_-YHd-B",
    tag: "Seismology",
    abstract: `When only direct-waves are inadequate, different combinations of both direct- and refracted-waves are used to determine hypocentral parameters of local earthquakes. Compared with only direct-waves, the addition of refracted-waves tends to increase errors of hypocentral parameters. This is true especially when the velocity structure of the region under investigation is not known. We use an accurate and fast algorithm to determine the hypocentral parameters based on an optimum 1-D velocity model yielding a minimum misfit error in media with multiple refracted-waves as first arrivals. Using the algorithm, we relocated earthquakes that occurred beneath the Parkfield region of California during the period between January 2000 and December 2000. The shallow part of the velocity model used in the study area has high velocity contrast among layers. Therefore, refracted-waves are recorded as first-arrival phases at most stations around the region for events of shallow focal depths (less than 3km). The study area covers the transition between the creeping segment of San Andreas Fault (SAF) to the northwest and the locked segment to the southeast. Accuracy test for the algorithm was conducted using some reference models. We compare the inverted hypocentral parameters with those determined by previous studies using HYPOINVERSE and the HypoDD. The epicentral distributions of the three methods show a close relationship with the regional fault distribution. However, compared to HypoDD, the epicentral distribution of HYPOINVERSE shifted slightly along the fault lines while the epicentral distribution of VELHYPO moved further in the same direction. The result of VELHYPO suggests that the dip of San Andreas Fault is 6-10 degrees SW while the results of HYPOINVERSE and HypoDD suggest that the dip of San Andreas Fault is nearly vertical and/or 3-7 degrees NE. This study supports the result of previous studies that San Andreas Fault is non-vertical but dips to southwest as part of a possible propeller-shape.`
  },
  {
    id: 10,
    title: "Data Analysis and Result Computation (DARC) Algorithm for Tertiary Institutions",
    authors: "Abel U. Osagie and Abu Mallam",
    journal: "Journal of Computer Engineering",
    volume: "14(1)",
    pages: "63–69",
    year: 2013,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1JpV0tDhmO3qB-7A3sysi_rUMseecBtv5",
    tag: "Educational Technology",
    abstract: `Tertiary institutions (e.g., Universities, Polytechnics and Colleges of Education) are expected to manage and preserve data of both present and past students. These data include general information about students as well as examination results at any or all stages of studentship. Analysis of student data can be used to inform solutions to a wide variety of educational challenges like exploring group differences, gender representation, ethnic representation, and growth over time. However, data management and examination result computation of large population of students can be rigorous time-consuming and prone to errors. Information management technology offers a comprehensive portfolio of students academic record to be available in real-time to students and professionals. That a comprehensive solution for use in many tertiary institutions is not yet common presents a unique opportunity for researchers to help shape the future of this technology. We introduce a Fortran algorithm for Data Analysis and Result Computation (DARC). The algorithm analyzes student data as well as computes examination results of all students in a department at once. DARC reads particular spreadsheet formats of students information data, semester scores and previous academic records, after which it outputs, among others, analysis of students information, comprehensive result format for students showing grade point averages (GPA) and updated cumulative grade point averages (CGPA), summary of academic records including log of carry over courses, log of carry over courses that have been cleared, log of outstanding courses and log of outstanding courses that have been cleared. Using synthetic record of some students, we validate the reliability of the algorithm by conducting accuracy tests. The algorithm is flexible and can be suitably modified to manage and preserve academic and general records of both present and past students in any tertiary institution.`
  },
  {
    id: 11,
    title: "Groundwater Potential Zonation Through Integration of Remote Sensing, Geographic Information Systems and AHP Techniques in FCT Abuja",
    authors: "Farouq Ado Umar, Mallam Abu, and Osagie Abel U.",
    journal: "Science & Technology Asia",
    volume: "31(1)",
    pages: "282–313",
    year: 2026,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1f9EBpJ_NL3hsR-XvznSpj0h6tBDaHYiD",
    tag: "GIS/Remote Sensing",
    abstract: `Groundwater is a vital freshwater resource supporting domestic, agricultural, and industrial demands, especially in semi-arid regions with limited surface water. This study maps groundwater potential zones in the Federal Capital Territory (FCT), Abuja, Nigeria, using an integrated approach combining Remote Sensing (RS), Geographic Information Systems (GIS), and the Analytical Hierarchy Process (AHP). These methods enable wide spatial coverage and objective analysis where conventional data are scarce. The study uses thematic datasets—slope, drainage density, lineament density, rainfall, topographic wetness index (TWI), land use/land cover (LULC), geology, and soil type—derived from satellite imagery, government sources, and field surveys (2015–2024). Parameters were weighted with AHP, processed in ArcGIS 10.7.1, and overlaid to produce a composite groundwater potential map. Results show steep slopes dominate over 80% of the area, limiting recharge, while only 2.29% favors infiltration. Moderate to low drainage density supports balanced recharge, while higher densities restrict it. Moderate lineament density aids recharge, though high density zones risk contamination. Most areas have low TWI, with small recharge hotspots. Vegetation dominates land cover, supporting infiltration, while urbanization hinders it. Overall, the model identifies high, moderate, and low potential zones, supporting sustainable groundwater management.`
  },
  {
    id: 12,
    title: "Delineation of depth to basement and subsurface structures beneath the Gerad Graben, Western Sirt Basin, Libya, from gravity and aeromagnetic data",
    authors: "Eshanibli A., Ismail Nur Azwin, Ghanush H. B., Dugdug Abdullatif, Osagie Abel U., Khalifa Nabil, Aushah Abed Alrauf M., Khalf Khiri A.",
    journal: "Energy Geoscience",
    volume: "6",
    pages: "",
    year: 2025,
    doi: "10.1016/j.engeos.2025.100468",
    download: "https://drive.google.com/uc?export=download&id=1jNfAc1IkOorBYEE31_SHRx75m1upiehL",
    tag: "Potential Field Methods",
    abstract: `This study integrates gravity and aeromagnetic datasets to delineate basement depth and characterise the subsurface structural framework of the Gerad Graben in the western Sirt Basin, Libya. Techniques including high-pass filtering, Centre for Exploration Targeting (CET) edge detection, Source Parameter Imaging (SPI), and Euler Deconvolution (ED) were applied to residual gravity and residual reduced-to-pole (RTP) magnetic data to enhance fault mapping and basement morphology. Tests of various cutoff wavelengths show that 10 km for gravity and 15 km for magnetic data provide optimal resolution of shallow structures while preserving deeper trends. Forward 2D GM-SYS modelling and Werner Deconvolution further constrained the geometry and depth of intrusive bodies and fault systems. Results reveal a structurally complex graben with NE-SW, NW-SE, ENE-WSW, and N-S trending faults, indicating multiphase tectonic deformation. Graben-bounding faults show displacement values of 600–4290 m, and basement depths in the central depocenter reach 4275–4300 m, validated by well NTF-50. Magnetic anomalies indicate intrusive igneous bodies, including NW-SE-trending sills and dikes, associated with the Tibesti and Al Haruj volcanic provinces. These intrusions likely caused localised heating, uplift, and fault reactivation. The integrated interpretation supports a tectono-magmatic evolution involving successive rifting phases from the Paleozoic to Cenozoic, influenced by inherited Precambrian structures. These features, coupled with substantial sediment infill and magmatic activity, enhance the hydrocarbon potential of the Gerad Graben, suggesting the presence of structural and stratigraphic traps within the broader of Sirt Basin petroleum system.`
  },
  {
    id: 13,
    title: "Groundwater Mapping Through Integration of Resistivity Survey, Remote Sensing, Geographic Information Systems and AHP Techniques in Bwari Area Council, FCT Abuja, Nigeria",
    authors: "Farouq Ado Umar, Mallam Abu, and Osagie Abel U.",
    journal: "International Journal of Innovative Science and Research Technology (IJISRT)",
    volume: "10(11)",
    pages: "1337–1375",
    year: 2025,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1weDXX-nA5W7cQf4FUh5-GEbd2_OU4FGF",
    tag: "Hydrogeophysics",
    abstract: `This study presents an integrated, multi-criteria approach to delineating groundwater potential zones in the Bwari Area Council, Federal Capital Territory, Abuja, Nigeria, employing a combination of Vertical Electrical Sounding (VES) resistivity surveys, remote sensing, Geographic Information Systems (GIS), and the Analytic Hierarchy Process (AHP). Using satellite imagery, DEMs, digitized maps, and field observations, thematic layers—rainfall, geology, slope, drainage density, land use/land cover, lineament density, soil type, and topographic wetness index—were generated and validated through GIS and remote sensing techniques. Weights were assigned to each factor using AHP, prioritizing parameters based on their hydrogeological significance. Thematic layers were integrated via weighted overlay analysis in ArcGIS to produce a spatially explicit groundwater potential map. Subsurface information was acquired through VES at 23 locations, with resistivity data interpreted to characterize aquifer properties (resistivity, thickness, depth, and overburden). The results reveal a dual aquifer system, comprising a shallow weathered zone and a deeper fractured basement aquifer, with groundwater occurrence predominantly controlled by secondary porosity features. Moderate-to-high groundwater potential zones were found to constitute over 85% of the study area, with high-potential regions associated with thick, weathered, and fractured lithologies, low drainage density, gentle slopes, and favourable land cover. Comparative analysis between the integrated thematic (RS/GIS/AHP) and aquifer-parameter (VES) models yielded a high correspondence (78.7%), confirming the reliability of the multi-criteria method and underscoring the importance of combining surface and subsurface data. The study advances methodological frameworks for groundwater assessment in crystalline basement terrains and provides a robust scientific basis for sustainable borehole siting, groundwater resource development, and land-use planning. The approach is replicable in similar hydrogeological settings, offering important implications for water resource management in data-scarce, complex geological environments.`
  },
  {
    id: 14,
    title: "Hydrogeological Evaluation of Abuja Municipal Area Council (AMAC) Using Vertical Electrical Sounding (VES)",
    authors: "Farouq Ado Umar, Mallam Abu, and Osagie Abel U.",
    journal: "International Journal of Innovative Science and Research Technology (IJISRT)",
    volume: "10(11)",
    pages: "2178–2200",
    year: 2025,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1TU1O9bic-RphIFkwouQ21sw2-cdSW4jV",
    tag: "Hydrogeophysics",
    abstract: `This study presents an integrated hydrogeological assessment of the Abuja Municipal Area Council (AMAC), Nigeria, using Vertical Electrical Sounding (VES) in conjunction with borehole lithological data to delineate subsurface stratigraphy and evaluate groundwater potential within the basement complex terrain. Twenty VES surveys conducted across key locations revealed a consistent geoelectric sequence comprising topsoil, lateritic or clayey overburden, a saprolitic weathered basement, a partially weathered gneissic horizon, and an underlying fractured crystalline basement. The principal curve types identified (KQ, HQ, QH, KA, KAQ, and KHA) indicate diverse hydrostratigraphic conditions and structural controls on groundwater occurrence. Correlation of VES interpretations with borehole logs demonstrated strong spatial agreement, confirming the reliability of the integrated geophysical-geological approach. Results show that the principal aquifer horizon occurs within the fractured basement at depths of approximately 38–70 m, where fracture zones and weathering intensity significantly enhance groundwater storage and yield. Thick saprolitic and partially weathered units serve as important recharge pathways and secondary storage zones, particularly at sites such as AMAC03, AMAC09, AMAC17, and AMAC20. Lower deep resistivity values at sites including AMAC18 and AMAC19 suggest zones of pronounced fracturing with higher yield potential, whereas shallow, highly resistive basement signatures indicate limited groundwater prospects dependent on discrete fracture systems. The study underscores the hydrogeological significance of overburden structure, secondary porosity, and fracture connectivity in controlling groundwater availability across AMAC. The integrated methodology enhances the accuracy of aquifer delineation and provides a robust framework for sustainable groundwater exploration and resource management in crystalline basement terrains. Future work should include expanded geophysical survey coverage, advanced 2D/3D imaging, and integration of hydrogeological models with regional water demand projections to support long-term groundwater security.`
  },
  {
    id: 15,
    title: "Characterization of hydrothermal alteration zones in parts of north-central basement complex of Nigeria for solid mineral deposits",
    authors: "Bwamba Jonah Ayuba, Abu Mallam and Abel U. Osagie",
    journal: "Earth Sciences Pakistan (ESP)",
    volume: "8(2)",
    pages: "72–79",
    year: 2024,
    doi: "10.26480/esp.02.2024.72.79",
    download: "https://drive.google.com/uc?export=download&id=1Ur7fzqRuq_9tr19lgE1otsTeKMlz9r1N",
    tag: "Potential Field Methods",
    abstract: `This study aimed at mapping the lithological formations and hydrothermally altered zones that are fruitful for the mineral potential in parts of the north-central basement complex of Nigeria using aeroradiometric data. The resulting radioelement of uranium (eU), thorium (eTh) and potassium (K%) anomaly data were subsequently used to depict the lithologies and hydrothermal alteration zones using ternary and potassium to thorium ratio imageries respectively. The abundance of K, eTh and eU varies in proportion of 0.12 to 4.37 %, 5.49 to 29.41 ppm and 0.49 to 8.29 ppm. The potassium to thorium ratio ranges from 0.01 to 0.38 %ppm revealing the hydrothermally altered zones to be around Dadabiri, Pai, Kwali, Gao and Tagwai. Hence, the prominent minerals identified in the study include albite (feldspar), granite, dolerite, gold and muscovite. The distribution and extent of these mineralized zones fall within a broad northeast-southwest trending axis.`
  },
  {
    id: 16,
    title: "The Integrated Geophysical Study for Delineating Cu-Au Sulfide Deposits in Ruwan Gora Anka Area, Northwestern Nigeria",
    authors: "Omatola Samson Pascal, Abu Mallam, Abel U. Osagie, Adeeko Tajudeen O.",
    journal: "Earth Sciences Pakistan (ESP)",
    volume: "8(1)",
    pages: "70–74",
    year: 2024,
    doi: "10.26480/esp.01.2024.70.74",
    download: "https://drive.google.com/uc?export=download&id=1zFSzXzOdHZAq7Yk4TR1j5RKot-5m0HnT",
    tag: "Potential Field Methods",
    abstract: `The Copper-Gold (Cu-Au) ore-bearing veins in Ruwan Gora, Anka, were studied using ground magnetic, resistivity, and induced polarisation (IP) geophysics methods. The study indicated that shallow/deep tectonic structures in the Precambrian Basement Complex may retain sulphide ores, while shallow granitic intrusive/volcanic rocks have high magnetic susceptibility values. Basement rock ore-bearing veins have susceptibilities of less than or equal to 50 nT because of the removal of IGRF, resistivity of greater than or equal to 100 ohm-m, and IP of greater than 203 ms. The ores electrical data demonstrates mineral zoning. High and low magnetic anomalies which amplitudes of 50nT and -50nT reside in the examined area. This is commendable given the slight magnetic anomaly. The residual magnetic field intensity map, down to the Interpreted Structural Map with an identification number, indicated considerable anomalies with trends in the NE-SW and N-S and few in E-W ones, which matched various structural trends in the region. IP and resistivity models identified shallow veins and bodies with considerable resistivity and chargeability. Large charged bodies were detected at a depth of greater than or equal to 60m. Most magnetic anomalies examined by the IP survey are charged, and their chargeability increases with depth.`
  },
  {
    id: 17,
    title: "Integrated Geophysical Investigation for Tin Ore Mineralization in Parts of Kafanchan, Middle Benue Trough, Nigeria",
    authors: "Omatola Samson Pascal, Abu Mallam, Abel U. Osagie, and Adeeko Tajudeen O.",
    journal: "Asian Journal of Geological Research",
    volume: "7(3)",
    pages: "408–424",
    year: 2024,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1GC0wNe2hsGGjwy99mf922LdjZ1BsdLcm",
    tag: "Potential Field Methods",
    abstract: `By combining the results of the two geophysical techniques in parts of Gidan Waya Kafancha Kaduna State, numerous linear structures, possibly veins harbouring ore mineralisation, were discovered. These veins have varying electrical characteristics, some being conductive and others being non-conductive. Furthermore, certain veins are conductors within a resistive host, whereas others are located within a conductive host. The research region had approximately 30 conductive bodies (veins), most of which trended north-south direction and ranged in length from less than 25 meters to more than 150 meters. These discovered veins were shown on mineral prospecting maps. After careful consideration, 30 locations were chosen for the prospective ERT/IP survey generated from the EM-VLF, and 25 drilling points were derived from the ERT/IP dataset obtained from the inversion model, which is the priority drilling point.`
  },
  {
    id: 18,
    title: "Application of Transient Electromagnetic Method for Mapping Deep-Seated Sulphide-rich Zones in High-Resistivity Settings: A Case Study in Tsauni, Northcentral Nigeria",
    authors: "Omatola Samson Pascal, Abu Mallam, Abel U. Osagie, and Adeeko Tajudeen O.",
    journal: "Asian Journal of Geological Research",
    volume: "7(3)",
    pages: "388–407",
    year: 2024,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1KDQSfOtbxoj7Fsb2LWjTANZDBN4OeqRl",
    tag: "Potential Field Methods",
    abstract: `The massive form of base metals in diverse geological settings holds greater economic significance than their disseminated counterparts, necessitating the distinction between massive and disseminated kinds. The sulphide mineralization in the area is recognized as hydrothermal vein-related rather than volcanogenic massive sulphide type, and it is situated in a highly resistive environment which prompted the use of TEM because of its capacity for depth penetration, it reduces electromagnetic coupling, improves resolution, is less sensitive to geological noise, and can acquire data faster; hence, the galvanic approach alone is insufficient for locating deep-seated sulphide-rich zones because of its limitations in current diffusion, electromagnetic coupling and depth limitations. Twenty-two (22) moving loops (Slingram) were established with dimensions of 200m by 200m. Simulations of individual lines conducted with Maxwell software indicated a substantial electromagnetic plate exhibiting a pronounced southerly dip, extensive strike, and significant depth extension. Following the fundamental initial hypothesis, this delineated the conductive structures associated with the deep-seated, sulphide-rich zone. The Tsauni sulphide deposit is observable along a 1 km strike length and demonstrates considerable conductivity indicative of tungsten sulphide potential. This process is particularly evident in regions where the host rock geology exhibits high resistivity; which is highly applicable in mineral Exploration, hydrocarbon Exploration and geothermal Exploration. The greater the resistivity, the more pronounced the induced polarisation relaxation impact on the transient electromagnetic signal.`
  },
  {
    id: 19,
    title: "Comparative Assessment of Aquifer Vulnerability Near Major Dumpsites around Karu-Abuja and Keffi in Nasarawa State, Nigeria, Using Integrated Geophysical Methods",
    authors: "Anthony Okeh, Abu Mallam, Osagie Abel Uyimwen, Okwute Ojonoma Loretta",
    journal: "International Journal of Environment and Climate Change",
    volume: "14(12)",
    pages: "366–414",
    year: 2024,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1Cu80AYKQKzTr2WqbhVvLaNc_Rph9-lex",
    tag: "Hydrogeophysics",
    abstract: `This study investigates aquifer vulnerability to leachate infiltration near major dumpsites in Karu Abuja and Keffi, Nasarawa State, Nigeria, using integrated geophysical methods — Vertical Electrical Sounding (VES), 2-D Electrical Resistivity Tomography (ERT), Self-Potential (SP), and Very Low Frequency Electromagnetic (VLF-EM). The study area spans basement complex and sedimentary formations. Data were collected from nine VES points, four ERT profiles, ten SP profiles and sixteen VLF transverses using Ohmega Allied resistivity meter and a Gem VLF receiver. The measurements identified groundwater saturation zones and contamination pathways such as fractures and faults. Data interpretation employed tools such as WINRESIST, RES2DINV, GRAPHER, SURFER and KHFFILT. Results delineated five to six geoelectric layers, including, topsoil, clayey sand, weathered/fractured, and fresh bedrocks. Keffi's topsoil resistivity values (47.1-224.2 ohm-m, in depths greater than or equal to 2.1 m) indicate thicker overburden and better aquifer protective layers compared to Karu-Abuja's resistivity values (16.5-294.0 ohm-m, in depths greater than or equal to 0.5 m). Leachate infiltration is observed in both areas, with materials of low resistivity values ranging from (7.2 to 9.9 ohm-m, in depths greater than or equal to 7.7 m) and (2.8 to 9.6 ohm-m, in depths greater than or equal to 6.37 m) in Karu-Abuja and Keffi study areas respectively, interpreted as contaminated zones. Negative SP anomalies ranging from (-339.9 to -1.1 mV) and (-135 to -1.65 mV) attributed to electro-kinetic reactions, and high positive VLF current-density ranging from (5 to 10 %, in depths greater than or equal to 14 m), further corroborated contamination pathways. The study evaluated the Aquifer Protective Capacities (APC) of Keffi and Karu-Abuja, revealing that Keffi showed better protection compared to Karu-Abuja, with Keffi showing poor rating of 66%; along VES 1 (0.043 S), VES 4 (0.05 S), VES 5 (0.01 S) and VES 6 (0.02 S) and a moderate rating of 33.33 %, along VES 3 (0.29 S) and VES 4 (0.33 S). Only VES 2 (0.89), representing 16.6%, had a good rating. The Karu-Abuja study area showed poor APC rating of 66.6%, along VES 1 (0.0063 S) and VES 3 (0.002 S), and a weak rating of 33.3% along VES 2 (0.1 S). The findings emphasise the need for regular Environmental Impact Assessments (EIAs) and the installation of geo-synthetic clay liners at dumpsite bases to safeguard groundwater resources.`
  },
  {
    id: 20,
    title: "Comparative Assessment of Physicochemical and Bacteriological Parameters in Water Sources Near Major Dumpsites and Control Areas in Karu-Abuja and Parts of Nasarawa State",
    authors: "Anthony Okeh, Abu Mallam, Osagie Abel Uyimwen, Okwute Ojonoma Loretta",
    journal: "Asian Journal of Geological Research",
    volume: "7(3)",
    pages: "471–502",
    year: 2024,
    doi: "10.9734/ajoger/2024/v7i3182",
    download: "https://drive.google.com/uc?export=download&id=1KLBWlZsihE0Or6xQEiNSKQpK8MFITjTQT",
    tag: "Hydrogeophysics",
    abstract: `This study evaluated the physicochemical and bacteriological parameters in water sources near major dumpsites and control areas in Karu-Abuja and Nasarawa State, to determine and compare extent of pollution using multivariate statistical analysis and indexing approach. Nine water samples from boreholes, hand-dug wells, and streams were analysed using AAS and standard methods. The concentration of Ca2+, K+, Mg2+, Cu2+, Na+, Fe2+, Zn2+, F-, SO42-, CO32-, pH, EC, COD, DO and BOD are within permissible limits, while parameters such as Pb2+ which varies from (0.44 to 0.488 mg/l), Co2+ (0.226 to 0.44 mg/l), Mn2+ (20.73 to 27.144 mg/l), Cr2+ (1.28 to 1.68 mg/l) and Cd2+ (0.09 to 0.092 mg/l) exceeded this limits. Results from Pearson correlation analysis (p less than 0.05) showed positive correlations of r ranging from 0.5 to 1, indicating comparable sources of ions in the water systems. The Water Quality Index (WQI) for samples near dumpsites (177.72) indicated poorer quality compared to control areas (62.25). The study found that water samples from boreholes near control areas were suitable for domestic use with (WQI less than 48), in contrast with samples from streams and hand-dug wells (WQI greater than 100). The water samples near dumpsites showed higher heavy metal pollution indices 188.53 compared to control sites 176.96. Bacterial analysis showed elevated coliform counts too numerous to be estimated (TNTC) in borehole samples near dumpsites, while streams had the lowest counts (9-16 cfu/ml) attributed to continuous flow. E. coli, faecal strep, and Pseudomonas spp were absent in most samples, except for a minor presence of (02 cfu/ml) Pseudomonas spp in a Keffi hand-dug well. The decreasing dominance for major cations and anions near dumpsites and control areas are: K+ greater than Ca2+ greater than Cu2+ greater than Ni2+ greater than Na+ greater than Mn2+ greater than Mg2+ greater than Zn2+ greater than Co2+ greater than Cr2+ Pb2+ greater than Cd2+; anions: F- greater than SO42- greater than Cl- and K+ greater than Mn2+ greater than Ca2+ greater than Mg2+ greater than Cr2+ greater than Na+ greater than Cu2+ greater than Co2+ greater than Zn2+ greater than Pb2+ greater than Cd2+ greater than Ni2+; anions: Cl- greater than SO42- greater than F- respectively, attributed to anthropogenic and geogenic processes. Principal Component Analysis (PCA) accounted for over 92% of the total variance in water quality data. Hydrochemical plots identified mixed water types (Ca-Mg-HCO3 and Ca-Mg-SO4) with temporary hardness. The findings underscore the need for regular water quality monitoring and strategic siting of groundwater sources to mitigate contamination risks and protect public health.`
  },
  {
    id: 21,
    title: "Assessment of Aquifer Vulnerability Near a Major Dumpsite in Goshen City, Nasarawa State, Nigeria Using Integrated Geophysical Methods",
    authors: "Anthony Okeh, Abu Mallam, Osagie Abel Uyimwen, Okwute Ojonoma Loretta",
    journal: "Asian Journal of Geological Research",
    volume: "7(3)",
    pages: "439–470",
    year: 2024,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1miLiAJog7yk65xQEiNSKQpK8MFITjTQT",
    tag: "Hydrogeophysics",
    abstract: `This study utilized geophysical methods—including Vertical Electrical Sounding (VES), 2-D Electrical Resistivity Tomography (ERT), Self-Potential (SP), and Very Low Frequency-Electromagnetic (VLF-EM) to evaluate leachate migration into aquifer systems near a major dumpsite in Goshen City, Nasarawa State. The study area, located between latitudes 8 degrees 56 minutes 8.0874 seconds N and 8 degrees 56 minutes 8.232 seconds N and longitudes 7 degrees 40 minutes 52.1178 seconds E and 7 degrees 40 minutes 35.241 seconds E, comprises basement complex and sedimentary rock formations. Fifteen VES points, three 2-D ERT profiles, ten SP profiles, and ten VLF transverses were established at the dumpsite and a control site. Geophysical data were collected using an Ohmega Allied resistivity meter and a Gem VLF receiver. Data interpretation employed tools such as WINRESIST, RES2DINV, GRAPHER, SURFER and KHFFILT. These methods identified groundwater saturation zones and contamination pathways, including fractures and faults. Results identified five to six distinct layers, including Topsoil, clayey sand, weathered/fractured, and fresh bedrocks. Leachate infiltrated zones, with low resistivity values ranging from 1.6 to 35.3 ohm-m, were identified along twelve VES points, at an average depth of 15.8 m. Negative SP anomalies are attributed to leachate electro-kinetic reactions, while high positive VLF current-density in depths of 14 m are interpreted as electrical conducting paths. The percentage (80%) of the combined VES points indicating weak to poor aquifer protective capacity, suggests that the area is unsuitable for a dumpsite establishment. The study recommends continuous monitoring and the installation of geo-synthetic clay liners at the base of the dumpsite to safeguard groundwater resources from leachate infiltration.`
  },
  {
    id: 22,
    title: "Crustal Thickness Beneath Utako Abuja Using Receiver Function Analysis",
    authors: "Fasiku O. B., Mallam A., Osagie A. U.",
    journal: "Open Journal of Physical Science (OJPS)",
    volume: "4(2)",
    pages: "1–12",
    year: 2023,
    doi: "10.52417/ojps.v4i2.516",
    download: "https://drive.google.com/uc?export=download&id=1Awg_Bv-BH_XsCmM0IhDMlzrJc-dL1sfK",
    tag: "Seismology",
    abstract: `Understanding the Mohorovicic discontinuity (Moho depth) is crucial in unraveling the Earth's subsurface structure. In this research, we present the report of the crustal thickness and the ratio of the primary wave to the shear wave velocities (p-to-s) beneath the seismic station located at the Nigerian Geological Survey Agency (NGSA) Abuja using Receiver Function Analysis (RFA). The primary objective of this study is to determine the depth of the Moho boundary and gain insights into the geological properties of the Earth's crust and upper mantle beneath the receiver station. This analysis focused on teleseismic earthquakes that were recorded at the station between 2020 and 2021, with epicenter distances between 30 degrees and 90 degrees and magnitudes 5.5 or greater. The P wave Receiver Function (PRF) was modeled from iterative time domain deconvolution using the converted phases (Ps) at the Moho interface. The seismograms were rotated from the conventional components to the ZRT component and the vertical component was deconvolved from the transverse and radial components to extract the RF, which was stacked subsequently using the H-k stacking algorithm. Through the analysis of the seismic data, the result indicates a relatively shallow crust beneath the study area, estimated to approximately 33.15 plus or minus 1.74 km, with a p-to-s wave velocity ratio of 1.73 plus or minus 0.04, which suggests minimal impact from plate thinning or intrusion.`
  },
  {
    id: 23,
    title: "Review of Identified Shortcomings in Aquifer Vulnerability Assessments",
    authors: "Anthony Okeh, Abu Mallam, Osagie Abel Uyimwen, S. A. Ganiyu",
    journal: "Journal CleanWAS",
    volume: "7(1)",
    pages: "20–29",
    year: 2023,
    doi: "10.26480/jcleanwas.01.2023.20.29",
    download: "https://drive.google.com/uc?export=download&id=1GhZS-paKlQ5fx5KLCR8uM_fcMkfpmhjU",
    tag: "Hydrogeophysics",
    abstract: `Several studies have successfully carried out aquifer vulnerability evaluations using a combination of geophysical and biogeochemical methods. Unfortunately, some identified shortcomings have often led to inaccurate assessments. This review attempts to identify some of these drawbacks and suggest better ways to improve upon analysis and interpretation of results. Articles reviewed were sourced publicly and subjected to systematic analysis based on fundamental principles. The outcomes of each analysis were discussed, among which was a study that applied Ohmega Resistivity meter to acquire Self-Potential (SP) data without specifying the nature of electrode used. The result indicated large SP readings greater than or equal to 200mV attributed to high fluid flow. According to analysis, when copper stakes are used, spurious SP readings occur in contrast to lower SP values of roughly 10 mV when suitable non-polarizable electrodes of Cu/CuSO4 porous pots are utilized to collect SP data. The review made clear the importance of providing detailed explanation of the nature of materials used. Another study solely collected samples for groundwater quality assessments during dry season, ignoring the effects of seasonal variation on water parameters. This must have had an impact on the results of the investigations. Research examined the aquifer problems in Gosa area of Abuja, utilizing only the Vertical Electrical Sounding (VES) technique. The study suggested basaltic intrusion as probable cause of borehole failures in the area. Different research which incorporated VES and data from the hill-shaded Shuttle Radar Topography Mission (SRTM), suggested insufficient interconnectivity within the fractures as conditions controlling groundwater occurrence in the area. The study illustrated the need for integrating geophysical methods for effective target detection. To map the infiltration of leachate into the subsurface, a study applied only the VES technique. Studies, however, showed that the VES method only provided average resistivity readings, suppressing some features. The study suggested the combination of VES and 2-D imaging for more accurate results. Another study obtained data via the ADMT Groundwater Detector. At the interpretation stage, the author interpreted ADMT data as VES, which was perceived as inaccurate as their principles and methodologies are different. Another study was noted to have presented results without categorizing the Aquifer Protective Capacity (APC) rating in percentages (%). It was assessed that a framework that accurately categorized the APC of each transversal using common statistics guidelines would have made it simpler to understand and aided decision-making. Future research is advised to take some of the noted flaws into account in order to enhance data processing and interpretation.`
  },
  {
    id: 24,
    title: "Geoelectrical Investigation of Groundwater Potential in University of Abuja, Main Campus",
    authors: "Temitope R. Tijani, Abu Mallam, Abel U. Osagie",
    journal: "PhysicsAccess",
    volume: "3(2)",
    pages: "45–55",
    year: 2023,
    doi: "10.47514/phyaccess.2023.3.2.008",
    download: "https://drive.google.com/uc?export=download&id=10EjIdj1qFrkyyJHXmAiqdr40xU9-E99u",
    tag: "Hydrogeophysics",
    abstract: `Electrical resistivity techniques of geophysical prospecting have been used to evaluate the groundwater potential of the University of Abuja Health Services Centre at the main campus. This research aims to identify suitable locations for productive wells and boreholes, determine the depth of the bedrock, as well as measure resistivity and overburden thickness. The survey employed Vertical Electrical Sounding (VES) along five profiles, comprising fifty (50) VES stations covering the survey area. The resistivity data obtained are analysed using IPI2win software. The analysis of the resistivity data revealed that the survey area can be divided into four geoelectric layers: topsoil, clayey sand, weathered layer, and fresh basement. The resistivity values of these layers range from 38.7-1427 ohm-m, 16.2-310 ohm-m, 32.1-1714 ohm-m and 1007-9528 ohm-m respectively. The fresh basement layer was found to have an infinite thickness. Significantly, potential regions with low resistivity values indicating the presence of groundwater were identified at a depth of 18.3 m. Furthermore, the average overburden thickness in the study area was 35 m while the longitudinal conductance of the overburden ranges from 0.04 to 1.87 mho. Results obtained indicate the main aquifer in the area consists of a thick weathered layer of overburden and a weathered basement with relatively low resistivity, suggesting a potentially productive groundwater yield. This information is crucial for future planning and decision-making regarding the siting of wells and boreholes and the sustainable utilisation of groundwater resources in the University of Abuja main campus.`
  },
  {
    id: 25,
    title: "Groundwater Exploration using 2D Resistivity Imaging within Abuja Municipal Area Council, Nigeria",
    authors: "Ezeamaka Grace Ozioma, Mallam Abu and Osagie Abel Uyimwen",
    journal: "Science World Journal",
    volume: "17(1)",
    pages: "175–179",
    year: 2022,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1lDdbX8NN25t2ZzHFX3Z1ndRz1v5LyCEe",
    tag: "Hydrogeophysics",
    abstract: `The fast-growing population of Abuja, Nigeria has over-stretched the public water supply capacity of the city. Like in many expensive cities, people live mostly in a conurbation of towns within Abuja metropolitan area (like the Kurudu area) where the public water supply is inadequate. The inhabitants are compelled to explore other sources of water such as stream water, shallow well water etc for survival. Groundwater is a readily available source and its exploration becomes a necessity. In this research, a two-dimensional (2D) electrical resistivity imaging survey technique is carried out within the Kurudu area of the Abuja Municipal Area Council in Nigeria. The ABEM Terrameter (SAS 1000) with Schlumberger configuration is used to acquire resistivity data from eleven profiles (9 profiles laid vertically, each with a length of 122 m and two profiles laid horizontally of length 82 m and 40 m). The RES2DINV is used to interpret the data and to model the subsurface. Three geoelectric layers with varying resistivities are identified beneath the study area. The top layer which have been inferred to as the lateritic clay/sandy clay has resistivity range of 5 - 3500 Ohm meters (ohm-m) with thickness of 1.5 - 2.55 meters (m). The second layer comprises of the weathered/fractured basement with depths of 1.5 - 15.8 m and ranges in resistivity values between 1 ohm-m and 3000 ohm-m. The bedrock which makes the third layer at depths of 10 - 15.8 m has resistivity range of 1000 ohm-m to 3500 ohm-m. The result of the inverse resistivity model suggests the presence of an eleven-meter aquifer thickness in the western flank of the study area. The average depth of the subsurface is about 15 meters.`
  },
  {
    id: 26,
    title: "Note on the History of (Square) Matrix and Determinant",
    authors: "Babarinsa Olayiwola, et al.",
    journal: "UDMA Journal of Sciences",
    volume: "6(3)",
    pages: "177–190",
    year: 2022,
    doi: "",
    download: "https://drive.google.com/uc?export=download&id=1jSARkFj-8u13buhAG8BjdTxfP1Aj1lzn",
    tag: "Other",
    abstract: `This paper reviews the theory of matrices and determinants. Matrix and determinant are nowadays considered inseparable to some extent, but the determinant was discovered over two centuries before the term matrix was coined. Our review associate determinant with the matrix as part of linear systems but not with polynomials. Thus, the paper first gives the background on matrix with vast applications in all fields of study and then reviews the history of determinants which is based on its major contributors in chronological order from the sixteenth century to the twenty-first century.`
  },
  {
    id: 27,
    title: "Analysis of gravity and aeromagnetic data to determine structural trend and basement depth beneath the Ajdabiya Trough in northeastern Libya",
    authors: "Abdelhakim S. Eshanibli, Abel Uyimwen Osagie, Nur Azwin Ismail and Hussin B. Ghanush",
    journal: "SN Applied Sciences",
    volume: "3(228)",
    pages: "",
    year: 2021,
    doi: "10.1007/s42452-021-04263-7",
    download: "https://drive.google.com/uc?export=download&id=1ab_GrU0khuuCZcvmZrcYYHZOa286Ivbv",
    tag: "Potential Field Methods",
    abstract: `In this study, we analyse both ground gravity and aeromagnetic data in order to delineate structural trends, fault systems and deduce sedimentary thicknesses within the Ajdabiya Trough in Libya's northeast. A high-pass filter and a reduced-to-the-pole (RTP) transformation are applied to the gravity and aeromagnetic data respectively. Different filters are used to enhance the structural signatures and fault trends within the study area. The Werner deconvolution and source parameter imaging (SPI) techniques are applied to the RTP magnetic data for source depth estimation. Four well-data within the area are used as constraints in the two-dimensional forward modelling process. The results show that the Ajdabiya Trough is characterised by gravity anomaly highs and magnetic anomaly lows. The analysis of gravity data shows predominant Northeast-Southwest structural trends, whereas the analysis of magnetic data shows predominant North-South magnetic lineaments within the Ajdabiya Trough. The Euler deconvolution depth estimates of faults depths range between 1500 and 9500 m. The SPI estimates of the magnetic basement range between 2500 and 11,500 m beneath the study area (deepest beneath the Ajdabiya Trough). Constrained by the well-data, six major layers characterize the four profiles that are taken within the area. One of the profiles shows a high-density intrusion (about 4 km from the surface) within the sedimentary sequence. The intrusion may be the result of the rifting Sirt Basin which caused a weakening of the crust to allow for mantle intrusion.`
  },
  {
    id: 28,
    title: "Delineation of structure elements and the basement depth at the Jifara plain NW Libya using integration application of potential field dataset",
    authors: "Fouzie Trepil, Sufian Kahoul, Osagie Abel Uyimwen, Abdelhakim Eshanibli, Nur Azwin Ismail and Hussin Ghanoush",
    journal: "Acta Geodynamica et Geromaterialia",
    volume: "18(1)",
    pages: "83–91",
    year: 2021,
    doi: "10.13168/AGG.2021.0006",
    download: "https://drive.google.com/uc?export=download&id=1biV-2UwFXYpvxIegkDhUCGFkvY8ko-cq",
    tag: "Potential Field Methods",
    abstract: `In this study, the analysis of ground gravity data (from the Libyan Petroleum Institute) and aeromagnetic data (from the African Magnetic Mapping Project) are used to delineate the structure elements and basement depth within the Jifara plain, northwest Libya. A high-pass filter and a reduction-to-the-pole (RTP) transformation are applied to the gravity and aeromagnetic data respectively. The Total horizontal gradient and Centre for Exploration Targeting (CET) grid analysis are applied to gravity datasets. Werner deconvolution is applied to the RTP magnetic data. One 2-D forward modelling profile is applied to gravity and magnetic dataset. The results show gravity anomaly highs and magnetic anomaly with different structure trends. Werner deconvolution profile shows a high-density intrusion (about 1.8 km from the surface) within the sedimentary sequence. The intrusion may be the result of the Eocene volcanic activities near the Gharyan region. The 2-D model shows that the basement depth of Jifara plain ranges from 2.8 to 3.0 km. The integration results of the gravity and magnetic dataset reflect various periods of tectonic activities within Jifara plain and the adjacent area.`
  },
  {
    id: 29,
    title: "Structural Exploration of Aeromagnetic Data over Part of Gwagwalada, Abuja for Potential Mineral Targets Using Derivatives Filters",
    authors: "Priscillia Egbelehulu, Abu Mallam, Abel U. Osagie and Adewumi Taiwo",
    journal: "Journal of Geological Research",
    volume: "3(3)",
    pages: "44–51",
    year: 2021,
    doi: "10.30564/jgr.v3i3.3540",
    download: "https://drive.google.com/uc?export=download&id=1FUMxbEwWt3tBEZM5sv7bB8MihxVXVmnE",
    tag: "Potential Field Methods",
    abstract: `Aeromagnetic data are consistently used for economic interest targeting and geological mapping. Besides solving problems that are concerned with the basement, the method has become a useful tool in exploring minerals, hydrocarbons occurrence, groundwater investigations, and geothermal potentials. This study analyses aeromagnetic data from the Nigerian Geological Survey Agency acquired at 100 m terrain clearance over a section of Gwagwalada in Abuja. The study area spans longitudes 7.0875 degrees E to 7.1458 degrees E and latitude 8.9625 degrees N to 9.0 degrees N (about 27 km2). After a reduction to the equator (RTE) transformation, the data is downward continued by 50 m. Different filters are applied to outline area of alteration associated to mineral deposit. Regional geologic structures trend NE - SW. The application of vertical derivatives (FVD and SVD) to the RTE grid enhanced shallow structures which trend NE - SW. Horizontal gradients along the X- and Y- directions enhance geological contacts attributable to blind faults. The Tilt derivative (TD) accentuated fault lines which trend NE - SW.`
  },
  {
    id: 30,
    title: "Interpretation of Aeromagnetic Data of Part of Gwagwalada Abuja Nigeria for Potential Mineral Targets",
    authors: "Priscillia Egbelehulu, Abu Mallam and Abel U. Osagie",
    journal: "Journal of Geological Research",
    volume: "3(4)",
    pages: "30–35",
    year: 2021,
    doi: "10.30564/jgr.v3i4.3581",
    download: "https://drive.google.com/uc?export=download&id=12oMO-1nKVSNGLCLP2MhcevAS6CLKeWXS",
    tag: "Potential Field Methods",
    abstract: `This study analyzes aeromagnetic data over a section of Gwagwalada in Abuja. The data were obtained from the Nigerian Geological Survey Agency acquired at 100 m terrain clearance. The study area spans longitudes 7.0875 E to 7.1458 E and latitude 8.9625 N to 9.0 N (about 27 km2). The dataset was reduced to the equator (RTE) and downward continued by 50 m. Analytic signal filter was applied on TMI-RTE grid to detect the edges of the magnetic bodies present. The structure was observed to trend NE-SW. The CET lineament map reveals intersections such as junctions and corners on the map. This revealed structure liable for potential mineralization zone. Euler deconvolution technique applied over the transformed dataset ascertain the location and depth of the structure, having a maximum depth of about 421 m and a minimum of about 59 m. Variation in magnetic depth and susceptibility contrast is specified by the gridded SPI depth map.`
  }
];

